// Calls: healthCheckWorkspace()
// Checks: Telegram, AI, Google Sheets, Calendar, Products, BOM, Stock
const { healthCheckWorkspace } = require('./app/js/setup/healthCheck.js');
const result = await healthCheckWorkspace();
return [{ json: result }];

const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const h = $input.first().json;
await sendManagerAlert(`✅ Система готова до роботи (${h.checked_at?.substring(0,10)})`);
return $input.all();

const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const h = $input.first().json;
const issues = [];
if (!h.telegram?.connected) issues.push('❌ Telegram не підключено');
if (!h.ai?.connected) issues.push('❌ AI API не підключено');
if (!h.products_filled) issues.push('⚠️ Товари не заповнені');
if (!h.bom_complete) issues.push('⚠️ BOM не заповнено');
if (!h.stock_filled) issues.push('⚠️ Склад порожній');
await sendManagerAlert('⚠️ Проблеми системи:\n' + issues.join('\n'));
return $input.all();

const { getFailedOperationsSummary } = require('./app/js/utils/retryService.js');
const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const summary = getFailedOperationsSummary();
if (summary.failed > 0) {
  await sendManagerAlert(`⚠️ Неопрацьовані помилки: ${summary.failed} (очікують: ${summary.pending})`);
}
return [{ json: summary }];
